insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('46812499-46a5-482c-ac5c-b035b02929b3', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'black-river-gorges-hiking', 'activity'::activity_type, 'Black River Gorges Hiking', 'Hike the heart of the Black River Gorges National Park to discover secret waterfalls, endemic wildlife, and panoramic ridge views.', 'Explore with us the heart of the Black River Gorges and be amazed by its hidden treasures that gradually reveal themselves to you. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('3da3c977-1c1a-4ca4-8aa6-4e5146460df7', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'blue-safari-submarine-subscooter', 'activity'::activity_type, 'Blue Safari Submarine & Subscooter', 'Descend into the depths of the Indian Ocean by submarine or subscooter to explore reefs, corals, marine life and the wreck of ''Le Star Hope''.', 'Gradually discover the underwater world by observing the beauty of the Indian Ocean and its marine life. You will receive a briefing before boarding the submarine from a boat platform. As you descend into the depths, you will explore the reefs, the corals, the local marine wildlife, the wreck of ''Le Star Hope,'' and an ancient anchor from the 17th century at the bottom of the ocean.', 'Sea & water activities', 'Trou Aux Biches Costal Road', '75', 'Trou Aux Biches Costal Road', 't', '{English,French}'::text[], '{"Briefing before boarding","Pick-up and drop-off at all parts of the island"}'::text[], '{"Do not drink if you are going to drive","Arrive at the boarding point at least 15 minutes before the cruise start time"}'::text[], '{"Explore the reefs and corals","Observe local marine wildlife","See the wreck of ''Le Star Hope''","Discover an ancient 17th-century anchor at the bottom of the ocean"}'::text[], 'Full Refund up to 24 Hours', 'published'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{"startWindow": "09:00"}'::jsonb, '10', 'per_person', 'f', 'North', NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('2d78f6bf-902a-4296-ade4-5fa52a67cc65', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'casela-world-of-adventures', 'activity'::activity_type, 'Casela World of Adventures', 'Day trip to Casela World of Adventures, a 14-hectare nature and leisure park with safaris, zip lines, walking with lions and family activities.', 'Welcome to the adventure world of Casela. Join us for an unforgettable day filled with activities for the whole family! 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('9962c783-f94a-41b3-bc9f-db2980aefe6b', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'catamaran-cruise-3-northern-island-adventure', 'activity'::activity_type, 'Catamaran Cruise 3 Northern Island Adventure', 'A full day from Grand Baie exploring Île Plate with lagoon snorkeling, a gourmet lunch on board, relaxation at Île aux Gabriel, and sunset views of Coin de Mire.', 'Depart from Grand Baie for a full day exploring Île Plate. Enjoy crystal-clear lagoon snorkeling with incredible fish and coral varieties. A gourmet lunch is prepared on the spacious catamaran, followed by relaxation at Île aux Gabriel. The day concludes with sunset views of Coin de Mire''s spectacular cliffs.', 'Catamaran cruises', 'Grand Baie, Sunset Boulevard', '480', 'Grand Baie', 't', '{English,French}'::text[], '{"Lunch with salads","Garlic butter bread","Grilled chicken/fish/sausage","Water, Coke, beer, wine, local rum","Flaming banana","Fruit salads",Snorkeling}'::text[], '{"Do not drink if you are going to drive","Arrive 15 minutes before departure","Own transport users must find directions on Google Maps"}'::text[], '{"Île Plate (Northern Region)","Ile Aux Gabriel (Northern Region)","Coin de Mire (Northern Region)","Snorkeling (Northern Region)"}'::text[], 'Full refund up to 24 hours', 'published'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{"itinerary": [{"area": null, "tags": [], "title": "Grand Baie, Sunset Boulevard", "description": "Departure"}, {"area": null, "tags": [], "title": "Gabriel Island", "description": "Visit"}, {"area": null, "tags": [], "title": "Flat Island", "description": null}, {"area": null, "tags": [], "title": "Gunner''s Quoin", "description": "Snorkeling"}]}'::jsonb, '10', 'per_person', 'f', 'North', NULL, NULL, '2', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('59d694e1-e076-4cec-b761-b462687e26a0', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'catamaran-cruise-ile-aux-cerfs', 'activity'::activity_type, 'Catamaran Cruise – Ile Aux Cerfs', 'A full-day catamaran cruise from Trou D''eau Douce visiting the Grand River South East Waterfall, snorkeling, a BBQ lunch on board, and Ile aux Cerfs.', 'Enjoy a full-day catamaran cruise departing from Trou D''eau Douce on Mauritius''s east coast. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('177e8323-a359-4233-852a-c3a7ae083759', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'catamaran-sunset-cruise', 'activity'::activity_type, 'Catamaran Sunset Cruise', 'Sail peacefully through the stunning sunset over Grand Bay on a beautiful catamaran while relaxing with a refreshing cocktail.', 'Sail peacefully through the stunning sunset over Grand Bay on a beautiful catamaran while relaxing with a refreshing cocktail. The sunsets on the northwest coast of Mauritius are legendary, and the best way to experience them is from the ocean. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('4ffb45b2-365d-4884-afbc-84aca75de00f', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'catapseed-5-islands', 'activity'::activity_type, 'Cataspeed 5 Islands', 'Discover the stunning east coast of Mauritius with visits to the Grand River South East Waterfall, five beautiful islands, and incredible snorkeling in crystal-clear lagoons. Enjoy breathtaking scenery, spot vibrant marine life, and relax on an unforgettable CataSpeed cruise.', 'Your full-day cruise begins at the public jetty in Trou d''Eau Douce, where you''ll meet the crew before setting off to discover the stunning east coast of Mauritius. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('6e06520e-4032-4b08-b91e-0bfc76d442b0', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'chamarel-tour', 'activity'::activity_type, 'Chamarel Adventure Tour', 'A private day tour through Chamarel and the south-west, taking in the Trou aux Cerfs crater, Grand Bassin sacred lake, Black River Gorges, the Seven Coloured Earths, Chamarel Waterfall and rum factory, and Le Morne viewpoint.', 'Discover the beauty and charm of Chamarel with this adventure tour offering natural wonders including Grand Bassin Spiritual Lake, the enchanting Seven-Coloured Earth, the majestic Chamarel Waterfall, and the Chamarel Rum Factory. The experience provides breathtaking views of Black River Gorges and Le Morne Mountain. The journey begins at the dormant Trou aux Cerfs Volcano Crater in Curepipe, offering panoramic vistas. Next is Grand Bassin (Ganga Talao), a sacred lake with the impressive Lord Shiva statue, providing spiritual significance and cultural insights. Alexandra Waterfall is a serene spot with abundant natural surroundings. Black River Gorges presents lush greenery, endemic flora and fauna, scenic trails with waterfalls and deep valleys. The Seven Coloured Earths showcase multi-colored volcanic sand in shades from deep red to vibrant blue. Chamarel Waterfall is Mauritius'' highest waterfall cascading into a lush gorge. Rhumerie de Chamarel provides rum-making education with tastings of locally crafted spirits. The tour concludes at the Benitiers Island and Le Morne Mountain viewpoint, offering sweeping ocean and mountain vistas reflecting Mauritius'' essence.', 'Taxi Sightseeing tours', NULL, '420', NULL, 't', '{English,French}'::text[], '{"Pick up and drop off from any hotel or Airbnb in Mauritius","Private transportation to all the sights mentioned","An English/French-speaking driver to guide you and provide information"}'::text[], '{"Entry ticket fees (Seven Coloured Earth Geopark, Rum Factory)",Lunch}'::text[], '{"Trou aux Cerfs Volcano Crater (Curepipe)","Grand Bassin (Ganga Talao)","Alexandra Falls & Black River Gorges","Seven Coloured Earth of Chamarel","Chamarel Waterfall","Chamarel Rum Factory (Visit & Tasting)","Benitiers Island & Le Morne Mountain Viewpoint"}'::text[], NULL, 'draft'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{}'::jsonb, NULL, 'vehicle', 'f', NULL, NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('1172d187-6f22-488d-bb76-ba8c6a4715c7', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'cultural-north-tour', 'activity'::activity_type, 'Mauritius Cultural Tour', 'A relaxed private tour of northern Mauritius covering the L''Aventure du Sucre sugar museum, Chateau de Labourdonnais, Grand Baie, the Red Church of Cap Malheureux, Pamplemousses Botanical Garden, and the Pereybere and Bain Boeuf beaches.', 'Discover the cultural treasures of northern Mauritius through this relaxed private journey exploring historic estates, tropical gardens, charming coastal villages, and beautiful beaches. The tour visits L''Aventure du Sucre Museum and Chateau de Labourdonnais, followed by the seaside atmosphere of Grand-Baie and the iconic Red Church of Cap Malheureux. You''ll stroll through the lush Pamplemousses Botanical Garden and unwind at Pereybere and Bain Boeuf Beach. With private transport and a friendly local driver, this tour blends culture, history, and coastal beauty. The experience is flexible and personalized, allowing you to explore at your own pace.', 'Taxi Sightseeing tours', NULL, '330', NULL, 't', '{English,French}'::text[], '{"Pick up and drop off from any hotel or Airbnb''s in Mauritius","Private transportation to all the sights mentioned above","A friendly English/French-speaking driver to guide you and provide information","First child seat free of charge (upon request)"}'::text[], '{"Entry ticket fees to places such as the sugar museum, the chateau & the botanical garden",Lunch}'::text[], '{"L''Aventure du Sucre Sugar Museum","Chateau de Labourdonnais","Grand Bay Beach & Village","Red Church of Cap Malheureux","SSR (Pamplemousses) Botanical Garden","Pereybere & Bain Boeuf Beach"}'::text[], NULL, 'draft'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{}'::jsonb, NULL, 'vehicle', 'f', NULL, NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('4c1ec0a9-00ce-49d6-8554-da65bf3a74c6', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'custom-road-trip', 'activity'::activity_type, 'Custom Road Trip', 'Design your own day across Mauritius with the AI planner — one flat price per vehicle.', NULL, 'Taxi Sightseeing tours', NULL, '480', NULL, 't', '{}'::text[], '{}'::text[], '{}'::text[], '{}'::text[], NULL, 'published'::activity_status, NULL, NULL, NULL, '0', '2026-06-17 22:31:27.128993+00', '{}'::jsonb, '10', 'vehicle_custom', 't', NULL, NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('268a885f-c018-452e-add8-9cf72ecc2f60', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'deep-sea-fishing', 'activity'::activity_type, 'Deep Sea fishing', 'Fish for Blue Marlin, Dorado and other big game under the guidance of experienced skippers on well-equipped modern boats.', 'Whether you are a beginner or an expert, you will enjoy fishing for a Blue Marlin, a Dorado, or other large fish under the guidance of experienced skippers. The modern boats designed for deep-sea fishing are well equipped. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('56e84f5b-ac60-486c-8937-3aee22812365', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'encountering-the-whales-and-swim-with-dolphins-excursion', 'activity'::activity_type, 'Encountering the Whales and swim with Dolphins excursion', 'A West coast boat excursion to admire humpback or sperm whales and snorkel with dolphins, under the supervision of professional skippers and crew.', 'A unique experience creating memories to last for a lifetime! Immerse yourself in the adventure of a lifetime which will bring you into contact with strikingly beautiful scenery, unspoiled landscapes and wonderful marine animals. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('bfb6c5df-ccdc-4090-bd86-a1b7491c35b6', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'flat-island-gabriel-island-and-the-gunners-coin-by-speedboat-exclusive-basis-only', 'activity'::activity_type, 'Full Day 3 Northern Island Speed Boat with Lunch(BBQ)', 'A private speedboat day trip from Grand Bay to Flat Island, Gabriel Island and Gunner''s Coin, with snorkeling, BBQ lunch and beverages.', 'A private day trip by speedboat to visit three northern islands of Mauritius. Departure is from Grand Bay, with an approximately 45-minute journey to Flat Island for relaxation and snorkeling in the lagoons. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('419bcd80-9ba2-4cc8-adbe-db96d89831d2', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'helicotour', 'activity'::activity_type, 'Helicopter Tour of Mauritius', 'Discover Mauritius from above on a private helicopter flight departing from the Triolet base in the north, with three packages from a short scenic hop to a full island tour.', 'THE MUST (departing from Triolet, North): A short flight and memories forever etched in your mind. The route departing from the Triolet base includes a flyover of the northern landscapes and islets. Enjoy the bustling life of Grand-Baie seen from above and the boats lined up near the golden sand beach. Then fly over Coin de Mire, which dominates the north coast, and Ile Plate, home to various species of reptiles. The flight ends with a magnificent stretch over Ile d''Ambre, where the famous Saint-Geran was shipwrecked and which was the setting of Paul et Virginie by Bernardin de Saint-Pierre.
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('d4dcc848-ef41-4f8f-85db-14bbd3803a2c', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'hiking-at-the-tamarind-falls-7-cascade', 'activity'::activity_type, 'Hiking At The Tamarind Falls / 7 Cascade', 'Guided hike to Tamarind Falls (7 Cascades), the highest waterfall in Mauritius, through plateaus rich in plants and exotic birds.', '7 Cascades, also known as Tamarind Falls, is located near the small village of Henrietta, on the high plateaus of Mauritius, and its source originates from Rivière Tamarin. The 7 Cascades measure 293 meters/961 feet, making it the highest waterfall in Mauritius. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('4dc413ac-04ef-433b-b0c3-b93b224c6e05', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'hiking-le-morne', 'activity'::activity_type, 'Hiking Le Morne', 'Climb the UNESCO World Heritage Le Morne mountain to its ''V'' summit for spectacular views of turquoise lagoons and lush mountain ranges.', 'Discover the beauty and majesty of Morne Mountain as you climb from its base to the peak of the ''V'' summit while enjoying the spectacular landscape. 
