insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('2402ab1e-1695-4485-a120-561d08797854', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'north-beaches-tour', 'activity'::activity_type, 'Beach Hopping Tour (North Beaches)', 'An exclusive private beach-hopping day tour to five northern Mauritius beaches with complimentary beach chairs, umbrella, mat, snacks and drinks, and an English/French-speaking driver.', 'An exclusive private beach tour exploring five northern Mauritius beaches in a single day. Visitors are transported by dedicated chauffeur across Trou aux Biches, Mont Choisy, La Cuvette, Grand Bay, and Pereybere beaches. The experience includes complimentary beach chairs, umbrellas, mats, snacks, and refreshing drinks. Each beach offers distinct characteristics: Mont Choisy features crystal waters and marine life; Pereybere provides vibrant atmosphere with local cafes; Grand Bay offers water sports and shopping; Trou aux Biches delivers serene, family-friendly conditions; La Cuvette provides a secluded, tranquil escape. The driver assists with beach setup and provides English/French-speaking guidance throughout.', 'Taxi Sightseeing tours', NULL, '330', NULL, 't', '{English,French}'::text[], '{"Pickup and drop-off from any hotel/Airbnb in Mauritius","Private vehicle and transportation between beaches","English/French-speaking driver","Supermarket stop on route","One beach umbrella, two beach chairs, one beach mat (minimum)","Snacks and chilled soft drinks","First child seat (upon request)"}'::text[], '{"Lunch (though driver provides restaurant recommendations)","Entry tickets to visiting places","Additional beach chairs/umbrellas beyond specified amounts"}'::text[], '{"Trou aux Biches Beach","Mont Choisy Beach","La Cuvette Beach","Grand Bay Beach","Pereybere Beach"}'::text[], NULL, 'published'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{"itinerary": [{"area": "North Region", "tags": [], "title": "Grand Bay Beach", "description": null}, {"area": "North Region", "tags": [], "title": "Pereybere Beach", "description": null}, {"area": "North Region", "tags": [], "title": "Mont Choisy Beach", "description": null}, {"area": "North Region", "tags": [], "title": "Trou Aux Biches", "description": null}, {"area": "North Region", "tags": [], "title": "Cap Malheureux", "description": null}]}'::jsonb, '10', 'vehicle', 'f', NULL, NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('a9164fa6-a19b-4789-866f-0f967dcde449', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'north-tour', 'activity'::activity_type, 'Private North Tour Mauritius', 'Private full-day tour of North Mauritius with a driver-guide: Port Louis and its central market, the Pamplemousses Botanical Garden, Grand Baie and the red-roof church of Cap Malheureux.', 'Discover the beauty, culture, and history of North Mauritius on this private full-day tour. Travel comfortably with an experienced local driver-guide and explore some of the island''s most famous attractions.
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('2938b5c4-9734-4dfd-84c0-4bfc46e9facb', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'port-louis-city-tour', 'activity'::activity_type, 'Port Louis City Tour', 'A private, personalised tour through the capital Port Louis, taking in viewpoints, Hindu temples, the Caudan Waterfront, Chinatown and bazaar, the Citadel Fort and the Odysseo Oceanarium with an English/French-speaking driver.', 'Embark on a captivating journey through the heart of Mauritius with the Port Louis City Tour, a comprehensive exploration of the capital''s rich tapestry of history, culture, and contemporary allure. The tour begins at the Marie Reine de la Paix Viewpoint, a serene haven with sweeping views of Port Louis framed against the Moka mountain range. Next, visitors immerse themselves in the spiritual and architectural grandeur of vibrant Hindu temples adorned with intricate carvings and vivid colors. The Caudan Waterfront presents the modern face of Mauritius—a bustling promenade featuring shopping, dining, and entertainment with stunning harbor views. The journey continues through Chinatown''s narrow streets and traditional shops, the historic bazaar with its colors and scents, and museums providing deeper cultural understanding. The Citadel Fort, perched atop a hill, offers panoramic views spanning the cityscape and harbor. The tour concludes at the Odysseo Oceanarium, a state-of-the-art facility showcasing diverse marine life and aquatic ecosystems. Throughout the experience, visitors gain profound understanding of the island''s past and present through a private, personalized journey with an English/French-speaking driver.', 'Taxi Sightseeing tours', NULL, '360', NULL, 't', '{English,French}'::text[], '{"Pick up and drop off from any hotel or Airbnb in Mauritius","Private transportation to all sights","English/French-speaking driver to guide and provide information","First child seat (free of charge, upon request)"}'::text[], '{"Entry ticket fees to places (Blue Penny Museum, etc.)","Lunch (customers choose restaurants; driver offers recommendations)"}'::text[], '{}'::text[], NULL, 'published'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{"itinerary": [{"area": "Capital", "tags": [], "title": "Port-Louis Caudan Waterfront", "description": null}, {"area": "Capital", "tags": ["Market", "Bazzar"], "title": "Chinatown", "description": null}, {"area": "Capital", "tags": [], "title": "Citadel Fort", "description": null}, {"area": "Capital", "tags": [], "title": "Odysseo Oceanarium", "description": null}, {"area": "Capital", "tags": [], "title": "Tamil Temple", "description": null}]}'::jsonb, '10', 'vehicle', 'f', NULL, NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('dcac8588-b2f3-4802-959f-970d1aa88755', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'private-full-day-3-northern-islands-adventure', 'activity'::activity_type, 'Private Full Day 3 Northern Islands Adventure', 'Enjoy a private full-day catamaran cruise from Grand Baie to Île Plate, featuring lagoon snorkeling, a gourmet lunch served on board, relaxation at Île aux Gabriel, and breathtaking views of Coin de Mire.', 'Depart from Grand Baie on your private catamaran for a full-day cruise to Île Plate. Snorkel in the crystal-clear lagoon, home to vibrant coral reefs and a variety of tropical fish. Enjoy a delicious gourmet lunch served on board as you sail through the stunning turquoise waters. Relax on the pristine beach of Île aux Gabriel or unwind on the spacious catamaran at your own pace. End your unforgettable day with breathtaking views of the dramatic cliffs of Coin de Mire before returning to Grand Baie.', 'Private Cruises', NULL, '420', 'Grand Baie', 'f', '{English}'::text[], '{"Lunch with salads","Garlic butter bread","Grilled chicken/fish/sausage","Water, Coke, beer, wine, local rum","Flaming banana","Fruit salads",Snorkeling}'::text[], '{"Do not drink if you are going to drive","Arrive 15 minutes before departure","Own transport users must find directions on Google Maps"}'::text[], '{"Île Plate (Northern Region)","Ile Aux Gabriel (Northern Region)","Coin de Mire (Northern Region)","Snorkeling (Northern Region)"}'::text[], 'Free cancellation up to 24 hours before your activity for a full refund.', 'published'::activity_status, NULL, NULL, NULL, '0', '2026-07-13 17:01:55.137323+00', '{"itinerary": [{"area": null, "tags": [], "title": "Grand Baie, Sunset Boulevard", "description": "Departure"}, {"area": null, "tags": [], "title": "Gunner''s Quoin", "description": "Snorkeling"}, {"area": null, "tags": [], "title": "Gabriel Island", "description": "Visit"}, {"area": null, "tags": [], "title": "Flat Island", "description": "Sightseeing"}], "whatToBring": ["Comfortable shoes", "Sunglasses", "Hat", "Swimwear", "Change of clothes", "Towel", "Camera", "Sunscreen", "Snorkeling gear"], "importantInfo": ["Infants aged 1 to 4 go free of charge.", "All food is halal. Vegetarian meals must be requested in advance.", "Pickup and drop-off is available if the applicable option is selected.", "Public parking is available 60m from the meeting point. Please arrive early to secure a space. Contact our team on WhatsApp for the location.", "The itinerary may be adjusted due to weather, sea conditions, tides, or operational requirements for guest safety.", "The captain’s decisions regarding navigation, timing, and itinerary adjustments are final and made in the interest of guest safety.", "Guests using wheelchairs need to stand briefly to get on and off the shuttle boat, with our crew assisting, to access the catamaran.", "For their own comfort and security, guests are kindly requested to keep personal belongings with them at all times. The company cannot be held responsible for any loss, theft, damage, or misplacement of personal items during the tour."]}'::jsonb, '10', 'per_person', 'f', NULL, NULL, NULL, '7', 'f', 'f', '2');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('83ec6f71-6e52-4406-ad53-74ab45d1bd21', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'private-full-day-5-islands-tour-ile-aux-cerfs-with-lunch', 'activity'::activity_type, 'Private Full Day 5 Islands tour Ile Aux Cerfs with Lunch', 'Enjoy a private full-day speedboat excursion from Trou d''Eau Douce, visiting the GRSE waterfall, snorkeling among vibrant coral gardens, exploring the five islands, savoring a BBQ lunch, and relaxing on the beautiful northern beaches of Île aux Cerfs.', 'Embark on a private speedboat excursion from Trou d''Eau Douce for a full day of adventure and relaxation.
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('ca8a0ff4-e24d-4712-ac91-457ee60d6c04', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'private-full-day-catamaran-ile-aux-cerfs', 'activity'::activity_type, 'Private Full Day Catamaran Ile Aux Cerfs', 'Set sail on a private full-day catamaran cruise from Trou d''Eau Douce and experience an unforgettable day with a visit to the Grand River South East Waterfall, snorkeling in turquoise lagoons, a gourmet BBQ lunch on board, and a relaxing stop at the idyllic Île aux Cerfs.', 'Enjoy an exclusive full-day private catamaran cruise departing from Trou d''Eau Douce on Mauritius'' east coast. Cruise to the spectacular Grand River South East Waterfall, snorkel in crystal-clear waters, and savor a delicious BBQ lunch with beverages served on board. Continue to the idyllic Île aux Cerfs, where you can unwind on pristine white-sand beaches, swim in the turquoise lagoon, and soak up the beauty of this tropical paradise at your own pace.', 'Private Cruises', 'Trou D''eau Douce', '420', 'Route Royale Maho, Trou d''Eau Douce', 't', '{English}'::text[], '{"Salads and garlic butter bread","BBQ items: chicken, fish, sausage","Beverages: water, Coke, beer, wine, local rum","Dessert: flaming banana",Snorkeling}'::text[], '{"Water Activities (Parasailing etc)"}'::text[], '{"Ile aux Cerfs (Eastern Region)","GRSE Waterfall (Eastern Region)","Snorkeling (Eau Bleu)","Lunch BBQ & Drinks on board"}'::text[], 'Free cancellation up to 24 hours before your activity for a full refund.', 'published'::activity_status, NULL, NULL, NULL, '0', '2026-07-12 16:34:56.545211+00', '{"itinerary": [{"area": null, "tags": [], "title": "Route Royale Maho, Trou d''Eau Douce", "description": "Departure"}, {"area": null, "tags": [], "title": "Grand River South East Waterfall", "description": "Sightseeing"}, {"area": null, "tags": [], "title": "Ile aux cerfs", "description": "Snorkeling + BBQ Lunch & Drinks on Board"}, {"area": null, "tags": [], "title": "Ile aux cerfs", "description": "Swimming & relaxation"}], "startWindow": "09:00", "whatToBring": ["Comfortable shoes", "Sunglasses", "Hat", "Swimwear", "Change of clothes", "Towel", "Camera", "Sunscreen", "Snorkeling gear"], "importantInfo": ["Arrive at boarding point at least 15 minutes before the cruise start time", "Guests using own transport must not drink if driving", "All food is halal. Vegetarian meals must be requested in advance.", "Pickup and drop-off is available if the applicable option is selected.", "Public parking is available 60m from the meeting point. Please arrive early to secure a space. Contact our team on WhatsApp for additional information.", "The itinerary may be adjusted due to weather, sea conditions, tides, or operational requirements for guest safety.", "The captain''s decisions regarding navigation, timing, and itinerary adjustments are final and made in the interest of guest safety.", "Guests using wheelchairs need to stand briefly to get on and off the shuttle boat, with our crew assisting, to access the catamaran.", "For their own comfort and security, guests are kindly requested to keep personal belongings with them at all times. The company cannot be held responsible for any loss, theft, damage, or misplacement of personal items during the tour."]}'::jsonb, '10', 'per_group', 'f', 'East', NULL, NULL, '3', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('59b0f6e2-a847-4418-9e3a-695a333465e4', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'private-full-day-speed-boat-ile-aux-cerf-with-lunch', 'activity'::activity_type, 'Private Full Day Speed Boat Ile Aux Cerf with Lunch', 'Enjoy a full-day excursion on your own private speedboat to Île aux Cerfs — cruise turquoise lagoons, witness the Grande Rivière Sud Est waterfall, savour a BBQ lunch on Îlot Mangénie, and add on water activities at your leisure.', 'Enjoy an unforgettable experience with your own private boat trip to Île aux Cerfs.
