efore your activity for a full refund.', 'published'::activity_status, NULL, NULL, NULL, '0', '2026-07-13 17:16:14.291994+00', E'{"itinerary": [{"area": null, "tags": [], "title": "Black River", "description": "Departure"}, {"area": null, "tags": [], "title": "Tamarin", "description": "Secret Spot\\nDolphin Watching"}, {"area": null, "tags": [], "title": "Crystal Rock, Tamarin", "description": "Snorkeling"}, {"area": null, "tags": [], "title": "Benitier Island", "description": "Lunch on Board"}], "whatToBring": ["Comfortable shoes", "Sunglasses", "Hat", "Swimwear", "Change of clothes", "Towel", "Camera", "Sunscreen", "Snorkeling gear"], "importantInfo": ["Infants aged 1 to 4 go free of charge.", "All food is halal. Vegetarian meals must be requested in advance.", "Pickup and drop-off is available if the applicable option is selected.", "Public parking is available 60m from the meeting point. Please arrive early to secure a space. Contact our team on WhatsApp for the location.", "The itinerary may be adjusted due to weather, sea conditions, tides, or operational requirements for guest safety.", "The captain’s decisions regarding navigation, timing, and itinerary adjustments are final and made in the interest of guest safety.", "Guests using wheelchairs need to stand briefly to get on and off the shuttle boat, with our crew assisting, to access the catamaran.", "For their own comfort and security, guests are kindly requested to keep personal belongings with them at all times. The company cannot be held responsible for any loss, theft, damage, or misplacement of personal items during the tour."]}'::jsonb, '10', 'per_person', 'f', NULL, NULL, NULL, '5', 'f', 'f', '3');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('f286759a-7721-4414-b8fd-dc164eb3120c', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'private-shopping-tour', 'activity'::activity_type, 'Private Shopping Tour', 'All day or half a day: Shopping in Mauritius can be a wonderful experience. Traditional arts and crafts, as well as the finest luxury products, can be found in various shopping centers and boutiques.', 'All day or half a day: Shopping in Mauritius can be a wonderful experience. Traditional arts and crafts, as well as the finest luxury products, can be found in various shopping centers and boutiques.
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('fb842149-9737-469b-a116-4b2b25230456', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'private-south-east-tour', 'activity'::activity_type, 'Private South East Tour', 'Explore the South-East Tour and uncover Mauritius’ rich history, cultural heritage, and scenic hidden gems.', 'Discover the wonders of Mauritius on our South-East Tour, a captivating journey through the island’s history, culture, and natural beauty. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('46f8ee0b-3c53-4c77-9461-a8d6a237267e', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'scubadiving', 'activity'::activity_type, 'Scuba Diving', 'Explore the breathtaking underwater scenery of Mauritius, with colourful corals and a rich variety of fish in crystal-clear waters.', 'Diving in Mauritius provides an unforgettable and extraordinary experience as you explore breathtaking underwater scenery, where colorful corals form enchanting landscapes teeming with an astonishing variety of shimmering fish. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('e0a2004b-4f7a-46a2-95f7-c7866c4980c9', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'seaplane', 'activity'::activity_type, 'Fly Over the Underwater Waterfall: Mauritius Seaplane Tour', 'Take off barefoot from the turquoise lagoon at La Prairie beach and fly beside the famous underwater waterfall illusion, next to a UNESCO World Heritage site.', 'We have the privilege of flying over the UNDERWATER CASCADE daily. Our seaplanes take off from the beach of La Prairie, right next to this natural wonder. Just a few steps away, barefoot in the turquoise lagoon, you board the seaplane. Get ready to take off from the crystal-clear waters, beside a UNESCO World Heritage site. Comfortably seated next to the pilot, you will discover this famous illusion: a waterfall at the bottom of the Indian Ocean. It''s magical and majestic. The most photogenic view has captivated the entire world since its photos made their rounds on the internet. This natural treasure is truly something to see in person.', 'Air activities', 'Beach of La Prairie, Mauritius', '15', NULL, 't', '{English,French}'::text[], '{}'::text[], '{}'::text[], '{"Fly over the famous underwater waterfall illusion at the bottom of the Indian Ocean","Take off barefoot from the turquoise lagoon at La Prairie beach","Seated next to the pilot","Views beside a UNESCO World Heritage site","Three tour options: 15min (the short ambre), 30min (the Turquoise experience), 60min (the mythical east)"}'::text[], NULL, 'draft'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{}'::jsonb, NULL, 'per_person', 'f', 'North', NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('13fb9ed9-2386-43aa-8e8c-87dac1f5f9fb', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'shopping-tour', 'activity'::activity_type, 'Shopping Tour', 'Half-day or full-day shopping tour through Port Louis, Curepipe and Floréal, taking in arts and crafts, luxury boutiques, department stores and markets.', 'All day or half a day: Shopping in Mauritius can be a wonderful experience. Traditional arts and crafts, as well as the finest luxury products, can be found in various shopping centres and boutiques. There are also several department stores offering very attractive prices and vibrant markets where you can truly experience the rhythm of life in Mauritius. During this visit, you will have the opportunity to explore many places in an interesting day: Port-Louis, Curepipe and Floréal. Prices are per vehicle and not per person.', 'Taxi Sightseeing tours', 'Belle Mare Tours Ltd, Royal Road, Belle Mare, Mauritius. Pick-up and drop-off at all parts of the island.', NULL, NULL, 't', '{English,French}'::text[], '{"Full day transport to all the mentioned sites above","Pick-up and drop-off at all parts of the island"}'::text[], '{"Admission tickets","Lunch / meals (driver can recommend restaurants)"}'::text[], '{"Port-Louis (North West region)","Curepipe (Centre region)","Floréal (Centre region)"}'::text[], NULL, 'draft'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{}'::jsonb, NULL, 'vehicle', 'f', NULL, NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('4cadf649-b9db-4911-96f4-cc10d67aa981', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'skydive', 'activity'::activity_type, 'Tandem Skydiving in Mauritius', 'Tandem skydive from 10,000 feet over Mon Loisir''s sugarcane fields, freefalling at 200 km/h before gliding down over the lagoons and reefs of the Indian Ocean.', 'Enjoy the spectacular views of Mauritius with a tandem skydive. Soar through the skies while securely harnessed to your experienced instructor. Experience a 360 degree view of the stunning coastline, interior, and mountains before your jump. This adrenaline-pumping activity is suitable for both beginners and experienced thrill-seekers alike. At 10,000 feet, you''ll freefall at 200 km/h for a minute, then glide for 5 minutes before landing safely. Feel the rush of excitement as you plummet towards the earth surrounded by breathtaking panoramas. Take off from Mon Loisir''s beautiful sugarcane fields overlooking the lagoons and reefs of the Indian Ocean. After the exhilarating experience, relax and reflect on your adventure while enjoying refreshments at the drop zone. The whole skydiving excursion lasts about 1 hour, including ground training, 25 minutes of flight, freefall, and parachute descent. Celebrate your bravery and sense of achievement with friends and family who can witness your jump and cheer you on. Receive a tandem skydiving certificate and opt for a DVD of your jump as a keepsake at an additional cost. Make sure to book in advance to secure your spot for this unforgettable adventure in Mauritius.', 'Air activities', 'Take off from Mon Loisir; Belle Mare Tours Ltd, Royal Road, Belle Mare, Mauritius. Arrive at least 15 minutes before the start time.', '60', NULL, 't', '{English,French}'::text[], '{"Tandem skydive from 10,000 feet","Ground training","25 minutes of flight","Freefall and parachute descent","Tandem skydiving certificate","Refreshments at the drop zone","Pickup and drop-off at all island locations"}'::text[], '{"DVD of your jump (additional cost: Rs 5000)","Photos (additional cost: Rs 6500)","Do not drink if you are driving your own transport"}'::text[], '{"360 degree panoramic views of the coastline, interior, and mountains","Take off from Mon Loisir''s sugarcane fields overlooking the lagoons and reefs of the Indian Ocean","Freefall at 200 km/h for one minute","Glide descent for 5 minutes","Refreshments at the drop zone"}'::text[], NULL, 'draft'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{}'::jsonb, NULL, 'per_person', 'f', 'North', NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('1c5af259-7dca-4a18-9e53-3cf51e8c8b36', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'south-tour-mauritius', 'activity'::activity_type, 'Private South Tour Mauritius', 'Places to discover during this visit to the south: Trou Aux Cerfs (Volcan), Floréal (Shopping), Grand Bassin – Sacred lake of the Hindu temple, Black River Gorges – Viewpoint, Chamarel 7-color earth + waterfall, Viewpoint of Bénitier Island', 'In the highlands, discover the impressive Trou aux Cerfs, the crater of a volcano that has been extinct for 700,000 years. From there, you will have a stunning view of the mountainous ring of Mauritius.
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('144de1ad-786f-4dc3-89f2-e635716c0040', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'south-west-splendor-expedition', 'activity'::activity_type, 'South West Splendor Expedition', 'A six-hour private tour of the south-west coast featuring the Le Morne UNESCO World Heritage site and beach, the Baie du Cap / Maconde viewpoint, the World of Seashells Museum, and the Lavilleon Adventure Park.', 'Embark on a six-hour journey exploring the majestic Le Morne World Heritage Site, serene Le Morne Beach, breathtaking Baie du Cap/Maconde Viewpoint, the fascinating World of Seashells Museum, and thrilling Lavilleon Adventure Park. Experience exclusive, tailored moments with a private vehicle, complimentary child seat, and flexible start times between 7:30-9:30 AM. The tour unveils stories of bravery and freedom at Le Morne, a UNESCO World Heritage mountain symbolizing cultural significance. Le Morne Beach offers soft white sands and crystal-clear waters for relaxation. Baie du Cap presents dramatic coastal views where ocean meets rugged cliffs. The World of Seashells Museum showcases one of the largest shell collections. Lavilleon Adventure Park offers zip-lining, archery, and outdoor activities in lush greenery.', 'Taxi Sightseeing tours', NULL, '360', NULL, 't', '{English,French}'::text[], '{"Pick up and drop off from any hotel or Airbnb in Mauritius","Private transportation to all the sights mentioned","An English/French-speaking driver to guide you and provide information","Complimentary child seat"}'::text[], '{"Entry ticket fees to the World of Seashells Museum and Lavilleon Adventure Park",Lunch}'::text[], '{"Le Morne World Heritage Site","Le Morne Beach","Baie du Cap / Maconde Viewpoint","World of Seashells Museum","Lavilleon Adventure Park"}'::text[], NULL, 'draft'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{}'::jsonb, NULL, 'vehicle', 'f', NULL, NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('0067e1c1-e08c-4c1b-a2ea-d66e9e285d05', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'speed-boat-ile-aux-cerfs', 'activity'::activity_type, 'Full Day Speed Boat Ile Aux Cerf with Lunch', 'A full-day speedboat trip to Île aux Cerfs with turquoise lagoons, the Grande Rivière Sud Est waterfall, a BBQ lunch on Îlot Mangénie and optional water activities.', 'Enjoy an unforgettable experience with a boat trip to Île aux Cerfs. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('4ed33705-839e-4b55-8546-cfbbf516775e', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'swim-with-dolphins-south-tours-all-inclusive', 'activity'::activity_type, 'Swim with Dolphins & South Tours All Inclusive', 'Sunrise speedboat swim with dolphins at Tamarin, then a southern road tour to Chamarel''s Seven Colored Earth, Black River Gorges, Grand Bassin and a rum distillery.', 'Depart at 6 AM from your hotel to Tamarin, witnessing the sunrise over the Indian Ocean. Board a speedboat to swim with dolphins in their natural habitat while exploring the western lagoon. Engage in diving and observe marine life, followed by snorkeling to experience the vibrant underwater world. At 10:30 AM, travel by taxi to Chamarel to visit the Seven Colored Earth and the island''s highest waterfall. Experience panoramic views of the Black River Gorges, Grand Bassin, Trou aux Cerfs, and Floreal. Visit the Chamarel Rum Distillery for rum tasting before returning to your hotel.', 'Dolphin swims', 'Hotel pick-up (all island locations); activity at Tamarin Bay with southern Mauritius road tour.', '480', NULL, 't', '{English,French}'::text[], '{"Pick-up and drop-off at all parts of the island","Swimming with dolphins",Transport,"Snorkeling gear (masks, fins, snorkels)",Towels}'::text[], '{"Swimwear (must be worn before visit starts)","Entrance fees and lunch"}'::text[], '{"Tamarin Bay","Benitier Island viewpoint","Chamarel (Seven Colored Earth and waterfall)","Black River Gorges","Grand Bassin (Ganga Talao)","Trou aux Cerfs",Floreal,"Chamarel Rum Distillery"}'::text[], NULL, 'draft'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{}'::jsonb, NULL, 'per_person', 'f', 'West', NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('d29e7a9e-9197-4c05-afcc-ad9f370668c5', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'swimming-with-dolphins', 'activity'::activity_type, 'Swimming with Dolphins Only', 'Early-morning speedboat trip to Tamarin Bay to swim with wild dolphins in their natural habitat, followed by snorkeling over coral reefs.', 'Make your trip to Mauritius truly unforgettable with the magical experience of swimming alongside dolphins. Set off early at 7:30 AM on a speedboat and head to Tamarin Bay, where you''ll meet these incredible creatures in their natural habitat. Feel the thrill as you dive into crystal-clear waters and watch dolphins play just a few feet away. Listen to their calls, observe their graceful movements, and enjoy a unique moment of connection with nature. This extraordinary adventure will fill you with joy, wonder, and an unmatched sense of freedom.
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('f328f009-1ab5-442b-ab0a-90d052ffe3eb', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'swimming-with-dolphins-benitier-island-speedboat-all-inclusive', 'activity'::activity_type, 'Full day dolphin swimming Ile aux Bénitiers with lunch', 'Full-day speedboat excursion in western Mauritius: swim with dolphins, snorkel, visit Crystal Rock, and enjoy a barbecue lunch on Ile aux Benitiers.', 'This full-day speedboat excursion offers an immersive ocean experience in Mauritius''s western region. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('6527f2f3-5e9a-4823-956f-3079253e07d7', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'tea-tasting-tour', 'activity'::activity_type, 'Private South - Tea Tasting', 'Explore South Mauritius with a personal driver-guide, including Bois Chéri tea plantation/factory, Saint Aubin colonial house and rum distillery.', 'Bois Chéri is one of the most important tea factories on the island. You will discover the different stages of production while enjoying a nice cup of tea. You will have a personal driver-guide to take you on a tour and provide you with information, offering a personalized service. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('eae309cd-c243-4557-832b-102883ccc719', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'tea-wildlife-exploration', 'activity'::activity_type, 'Tea & Wildlife Exploration Tour', 'A private southern tour combining tea heritage and wildlife: the Bois Cheri tea factory and museum, the Domaine des Aubineaux colonial estate, La Vanille Nature Park with giant tortoises and crocodiles, and the Gris Gris coastal viewpoint.', 'Explore Mauritius in comfort and style with Taxi Service Mauritius''s exclusive Tea & Wildlife Exploration Tour. Our private tours ensure personalized attention as you journey through the island''s most enchanting destinations. With a dedicated vehicle and driver at your service, enjoy the freedom to explore at your own pace. At Bois Cheri Tea Factory & Museum, delve into the rich history of Mauritius'' tea industry. Witness the tea-making process from leaf to cup and savour the aroma of freshly brewed blends. Explore the museum and learn about the cultural significance of tea on the island. Nestled amidst lush sugarcane fields, Domaine de St Aubin offers a glimpse into Mauritius'' colonial past. Wander through the beautifully preserved estate, admiring its elegant architecture and vibrant gardens. Step back in time at Domaine des Aubineaux, a charming colonial house in the heart of a fragrant tea plantation. Marvel at the exquisite architecture and stroll through meticulously landscaped gardens. Prepare for an adventure at La Vanille Crocodile Nature Park, home to diverse wildlife. Encounter giant tortoises, colourful butterflies, and majestic crocodiles as you explore the lush surroundings. Marvel at the breathtaking beauty of Gris Gris Viewpoint, where rugged cliffs meet the endless expanse of the Indian Ocean. End your journey at Senneville Cliffs, a hidden gem offering sweeping vistas of Mauritius'' dramatic coastline.', 'Taxi Sightseeing tours', NULL, '360', NULL, 't', '{English,French}'::text[], '{"Pick up and drop off from any hotel or Airbnb''s in Mauritius","Private transportation to all the sights mentioned above","A friendly English/French-speaking driver to guide you","First child seat ordered is free of charge"}'::text[], '{"Entry ticket fees to places such as the Tea Factory & La Vanille Nature Park",Lunch}'::text[], '{"Trou aux Cerfs Volcano Crater","Grand Bassin (Ganga Talao)","Bois Cheri Tea Factory & Museum","Domaine des Aubineaux","La Vanille Nature Park","Gris Gris Viewpoint"}'::text[], NULL, 'draft'::activity_status, NULL, NULL, NULL, '0', '2026-06-19 20:14:04.421184+00', '{}'::jsonb, NULL, 'vehicle', 'f', NULL, NULL, NULL, '1', 'f', 'f', '0');
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('c0d11d15-ab7a-4ca0-9085-0af44c6ade2a', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'the-blue-cruise-ile-aux-cerfs-5-islands-visit', 'activity'::activity_type, 'Full Day 5 Islands tour Ile Aux Cerfs  with Lunch', 'A full-day speedboat excursion from Trou d''Eau Douce taking in the GRSE waterfall, snorkeling among coral gardens, five islands, a BBQ lunch and the beaches of northern Île aux Cerfs.', 'This speedboat excursion from Trou d''Eau Douce promises a total escape. 
insert into activities ("id", "operator_id", "slug", "type", "title", "summary", "description", "category", "location", "duration_minutes", "meeting_point", "pickup_available", "languages", "inclusions", "exclusions", "highlights", "cancellation_policy", "status", "seo_title", "seo_description", "rating_avg", "rating_count", "created_at", "extra", "daily_capacity", "pricing_mode", "is_custom_planner", "region", "lat", "lng", "min_advance_days", "is_airport_transfer", "is_hotel_transfer", "sort") values ('dcad49d8-35c3-4454-a6e6-cf96743b32b9', 'bb34e08d-d570-491e-8ff6-ca9d401b2a82', 'underwater-sea-walk-excursion', 'activity'::activity_type, 'Underwater Sea Walk Excursion', 'Walk on the ocean floor at a depth of 10-13 feet in a diving suit, accompanied by experienced instructors, to observe marine fauna and flora.', 'Equipped with a diving suit and accompanied by experienced instructors, dive into the underwater world at a depth of 10-13 feet for an unforgettable and enriching experience. 
